import jwt
import datetime
import secrets
from typing import Dict, Optional, Any
from functools import wraps
from flask import request, jsonify

SECRET_KEY = secrets.token_urlsafe(32)
ALGORITHM = 'HS256'
TOKEN_EXPIRATION_HOURS = 24
REFRESH_TOKEN_EXPIRATION_DAYS = 30

def generate_jwt_token(user_id: str, role: str, token_type: str = 'access') -> str:
    """
    Generate a JWT token for user authentication.
    
    Args:
        user_id: Unique identifier for the user
        role: User's role (e.g., 'admin', 'user', 'moderator')
        token_type: Type of token ('access' or 'refresh')
    
    Returns:
        JWT token as a string
    """
    if token_type == 'access':
        expiration = datetime.datetime.utcnow() + datetime.timedelta(hours=TOKEN_EXPIRATION_HOURS)
    else:
        expiration = datetime.datetime.utcnow() + datetime.timedelta(days=REFRESH_TOKEN_EXPIRATION_DAYS)
    
    payload = {
        'user_id': str(user_id),
        'role': str(role),
        'type': token_type,
        'exp': expiration,
        'iat': datetime.datetime.utcnow(),
        'jti': secrets.token_urlsafe(16)
    }
    
    token = jwt.encode(payload, SECRET_KEY, algorithm=ALGORITHM)
    return token

def verify_jwt_token(token: str, expected_type: str = 'access') -> Optional[Dict[str, Any]]:
    """
    Verify and decode a JWT token.
    
    Args:
        token: JWT token string
        expected_type: Expected token type ('access' or 'refresh')
    
    Returns:
        Decoded payload if valid, None otherwise
    """
    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_iat': True,
                'require': ['exp', 'iat', 'user_id', 'role', 'type', 'jti']
            }
        )
        
        if payload.get('type') != expected_type:
            return None
            
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None
    except Exception:
        return None

def refresh_access_token(refresh_token: str) -> Optional[str]:
    """
    Generate a new access token using a valid refresh token.
    
    Args:
        refresh_token: Valid refresh token
    
    Returns:
        New access token if refresh token is valid, None otherwise
    """
    payload = verify_jwt_token(refresh_token, expected_type='refresh')
    if not payload:
        return None
    
    return generate_jwt_token(payload['user_id'], payload['role'], token_type='access')

def require_auth(required_role: Optional[str] = None):
    """
    Decorator to protect routes with JWT authentication.
    
    Args:
        required_role: Optional role requirement for access
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            auth_header = request.headers.get('Authorization')
            
            if not auth_header:
                return jsonify({'error': 'Missing authorization header'}), 401
            
            parts = auth_header.split()
            if len(parts) != 2 or parts[0].lower() != 'bearer':
                return jsonify({'error': 'Invalid authorization header format'}), 401
            
            token = parts[1]
            payload = verify_jwt_token(token)
            
            if not payload:
                return jsonify({'error': 'Invalid or expired token'}), 401
            
            if required_role and payload.get('role') != required_role:
                return jsonify({'error': 'Insufficient permissions'}), 403
            
            request.user_id = payload['user_id']
            request.user_role = payload['role']
            
            return f(*args, **kwargs)
        return decorated_function
    return decorator

def login_user(user_id: str, role: str) -> Dict[str, str]:
    """
    Generate both access and refresh tokens for a user login.
    
    Args:
        user_id: User's unique identifier
        role: User's role
    
    Returns:
        Dictionary containing access_token and refresh_token
    """
    access_token = generate_jwt_token(user_id, role, token_type='access')
    refresh_token = generate_jwt_token(user_id, role, token_type='refresh')
    
    return {
        'access_token': access_token,
        'refresh_token': refresh_token,
        'token_type': 'Bearer',
        'expires_in': TOKEN_EXPIRATION_HOURS * 3600
    }

def get_token_payload(token: str) -> Optional[Dict[str, Any]]:
    """
    Get the payload from a token without full verification (for debugging only).
    Use verify_jwt_token for production.
    
    Args:
        token: JWT token string
    
    Returns:
        Decoded payload without verification
    """
    try:
        return jwt.decode(token, options={"verify_signature": False})
    except Exception:
        return None